    module Vector64 = Rt.Ref64.Vector

    let[@inline] container b o = Rt.Ref.read_table_opt b o 4
    let[@inline] shared_name b o = Rt.Ref.read_table_opt b o 6

    module Builder = struct
      type t = Rt.Builder.t

      let start b = Rt.Builder.start_table b ~n_fields:2
      let finish b = Rt.Builder.end_table b
      let add_container = Rt.Ref.push_slot 0
      let add_shared_name = Rt.Ref.push_slot 1
    end

    type obj = {
      container : string option;
      shared_name : string option;
    }

    let unpack b__ o__ : obj = {
      container = Rt.Option.fold ~none:None ~some:(fun s -> Some (Rt.String.to_string b__ s)) (container b__ o__);
      shared_name = Rt.Option.fold ~none:None ~some:(fun s -> Some (Rt.String.to_string b__ s)) (shared_name b__ o__);
    }

    let pack b__ (obj : obj) =
      let container' = Option.map (fun s -> Rt.String.create b__ s) obj.container in
      let shared_name' = Option.map (fun s -> Rt.String.create b__ s) obj.shared_name in
      let t = Builder.start b__ in
      let t = match container' with None -> t | Some off -> Builder.add_container off t in
      let t = match shared_name' with None -> t | Some off -> Builder.add_shared_name off t in
      Builder.finish t
  end

