  (* Table tflite.SignatureDef (//schema.fbs) *)
  and SignatureDef : sig
    type t

    module Vector : Rt.VectorS with type 'b elt := ('b, t) Rt.fb and type builder_elt := t Rt.wip

    module Vector64 : Rt.VectorS with type 'b elt := ('b, t) Rt.fb and type builder_elt := t Rt.wip

    val inputs : 'b Rt.buf -> ('b, t) Rt.fb -> ('b, TensorMap.Vector.t) Rt.fbopt
    val outputs : 'b Rt.buf -> ('b, t) Rt.fb -> ('b, TensorMap.Vector.t) Rt.fbopt
    val signature_key : 'b Rt.buf -> ('b, t) Rt.fb -> ('b, Rt.String.t) Rt.fbopt
    val subgraph_index : 'b Rt.buf -> ('b, t) Rt.fb -> Rt.UInt.t

    module Builder : sig
      type t

      val start : Rt.Builder.t -> t
      val finish : t -> SignatureDef.t Rt.wip
      val add_inputs : TensorMap.Vector.t Rt.wip -> t -> t
      val add_outputs : TensorMap.Vector.t Rt.wip -> t -> t
      val add_signature_key : Rt.String.t Rt.wip -> t -> t
      val add_subgraph_index : Rt.UInt.t -> t -> t
    end

    type obj = {
      inputs : TensorMap.obj array;
      outputs : TensorMap.obj array;
      signature_key : string option;
      subgraph_index : Rt.UInt.t;
    }

    val unpack : 'b Rt.buf -> ('b, t) Rt.fb -> obj
    val pack : Rt.Builder.t -> obj -> t Rt.wip
  end = struct
    type t

    module Vector = Rt.Ref.Vector

    module Vector64 = Rt.Ref64.Vector

    let[@inline] inputs b o = Rt.Ref.read_table_opt b o 4
    let[@inline] outputs b o = Rt.Ref.read_table_opt b o 6
    let[@inline] signature_key b o = Rt.Ref.read_table_opt b o 8
    let[@inline] subgraph_index b o = Rt.UInt.(read_table_default b o 12 ~default:(of_default 0L))

    module Builder = struct
      type t = Rt.Builder.t

      let start b = Rt.Builder.start_table b ~n_fields:5
      let finish b = Rt.Builder.end_table b
      let add_inputs = Rt.Ref.push_slot 0
      let add_outputs = Rt.Ref.push_slot 1
      let add_signature_key = Rt.Ref.push_slot 2
      let add_subgraph_index = Rt.UInt.(push_slot_default 4 ~default:(of_default 0L))
    end

    type obj = {
      inputs : TensorMap.obj array;
      outputs : TensorMap.obj array;
      signature_key : string option;
      subgraph_index : Rt.UInt.t;
    }

    let unpack b__ o__ : obj = {
      inputs = Rt.Option.fold ~none:[||] ~some:(fun v -> Array.map (fun x -> TensorMap.unpack b__ x) (TensorMap.Vector.to_array b__ v)) (inputs b__ o__);
      outputs = Rt.Option.fold ~none:[||] ~some:(fun v -> Array.map (fun x -> TensorMap.unpack b__ x) (TensorMap.Vector.to_array b__ v)) (outputs b__ o__);
      signature_key = Rt.Option.fold ~none:None ~some:(fun s -> Some (Rt.String.to_string b__ s)) (signature_key b__ o__);
      subgraph_index = subgraph_index b__ o__;
    }

    let pack b__ (obj : obj) =
      let inputs' = TensorMap.Vector.create b__ (Array.map (fun x -> TensorMap.pack b__ x) obj.inputs) in
      let outputs' = TensorMap.Vector.create b__ (Array.map (fun x -> TensorMap.pack b__ x) obj.outputs) in
      let signature_key' = Option.map (fun s -> Rt.String.create b__ s) obj.signature_key in
      let t = Builder.start b__ in
      let t = Builder.add_inputs inputs' t in
      let t = Builder.add_outputs outputs' t in
      let t = match signature_key' with None -> t | Some off -> Builder.add_signature_key off t in
      let t = Builder.add_subgraph_index obj.subgraph_index t in
      Builder.finish t
  end

  (* Table tflite.AddOptions (//schema.fbs) *)
  and AddOptions : sig
